CREATE VIEW public.v_interaction AS
 SELECT c.id,
    'CALL'::text AS type,
    c.status,
    c.agent_id,
    u.customer_id,
    c.disposition_id,
    c.opened_at,
    c.closed_at
   FROM (public.call c
     JOIN public."user" u ON ((u.id = c.agent_id)))
UNION ALL
 SELECT t.id,
    'TICKET'::text AS type,
    t.status,
    t.agent_id,
    u.customer_id,
    t.disposition_id,
    t.opened_at,
    t.closed_at
   FROM (public.ticket t
     JOIN public."user" u ON ((u.id = t.agent_id)));


